(async () => {
  try {
    const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

    // 1. パスワード入力フィールドを検索
    let passwordInput = document.querySelector('input[name="current_password"][type="password"]');

    // パスワード入力欄がない場合は「すでにステップ3（Email画面）かどうか」を判定
    if (!passwordInput) {
      let emailElement = null;

      // 方法1: href="/settings/email"
      emailElement = document.querySelector('a[href="/settings/email"]');

      // 方法2: data-testid="pivot" のタブからテキストで判定
      if (!emailElement) {
        const tabs = Array.from(document.querySelectorAll('a[role="tab"][data-testid="pivot"]'));
        emailElement = tabs.find(tab => {
          const text = (tab.textContent || '').trim();
          return text.includes('Email') || text.includes('メール') || text.includes('@');
        });
      }

      // 方法3: すべての tab からテキストで判定
      if (!emailElement) {
        const links = Array.from(document.querySelectorAll('a[role="tab"]'));
        emailElement = links.find(link => {
          const text = (link.textContent || '').trim();
          const span = link.querySelector('span');
          const spanText = span ? (span.textContent || '').trim() : '';
          return text.includes('Email') || text.includes('メール') ||
                 spanText === 'Email' || spanText === 'メール';
        });
      }

      if (emailElement) {
        // すでにメールアドレス設定の画面にいる想定なのでスキップ扱い
        return {
          didAction: true,
          reason: 'パスワード入力画面が表示されていませんが、メールアドレス欄が表示されているためスキップしました'
        };
      }

      return { didAction: false, reason: 'パスワード入力フィールドが見つかりませんでした' };
    }

    // 2. パスワードを取得（テンプレート変数は実行時に置換される前提）
    const rawPassword = '{{db_x_password}}';
    const password = (rawPassword || '').trim();

    if (!password || !password.trim()) {
      return { didAction: false, reason: 'db_x_password が指定されていません' };
    }

    // 3. パスワード欄に値を設定（React 対応）
    passwordInput.focus();
    passwordInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
    await sleep(200);

    const setter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value')?.set;
    if (setter) {
      setter.call(passwordInput, password);
    } else {
      passwordInput.value = password;
    }
    passwordInput.dispatchEvent(new Event('input', { bubbles: true }));
    passwordInput.dispatchEvent(new Event('change', { bubbles: true }));
    await sleep(300);

    // 4. Confirm ボタンを探して 1 回だけクリック
    let confirmButton = null;

    // まず同じセクション内を優先的に探す
    const container = passwordInput.closest('section,[role="dialog"],form') || document;
    const buttonsInContainer = Array.from(container.querySelectorAll('button, [role="button"]'));
    confirmButton = buttonsInContainer.find(btn => {
      const text = (btn.textContent || '').trim().toLowerCase();
      return text === 'confirm' || text.includes('confirm') || text.includes('確認');
    });

    // セクション内で見つからなければ全体から検索
    if (!confirmButton) {
      const allButtons = Array.from(document.querySelectorAll('button, [role="button"]'));
      confirmButton = allButtons.find(btn => {
        const text = (btn.textContent || '').trim().toLowerCase();
        return text === 'confirm' || text.includes('confirm') || text.includes('確認');
      });
    }

    if (!confirmButton) {
      return { didAction: false, reason: 'Confirm ボタンが見つかりませんでした' };
    }

    confirmButton.scrollIntoView({ behavior: 'smooth', block: 'center' });
    await sleep(200);

    // クリック（1回だけ）
    confirmButton.click();
    // React 用に MouseEvent も投げておく（多重クリックにはならない）
    confirmButton.dispatchEvent(new MouseEvent('click', {
      bubbles: true,
      cancelable: true,
      view: window
    }));

    await sleep(1000);

    return {
      didAction: true,
      reason: 'パスワードを入力して Confirm ボタンをクリックしました'
    };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})();

(async () => {
  try {
    // メールアドレス欄を検索（複数の方法を試す）
    let emailElement = null;

    // 方法1: href="/settings/email" のリンクを直接検索
    emailElement = document.querySelector('a[href="/settings/email"]');

    // 方法2: data-testid="pivot" で role="tab" の要素を検索し、テキストに "Email" が含まれるものを探す
    if (!emailElement) {
      const tabs = Array.from(document.querySelectorAll('a[role="tab"][data-testid="pivot"]'));
      emailElement = tabs.find(tab => {
        const text = (tab.textContent || '').trim();
        return text.includes('Email') || text.includes('メール') || text.includes('@');
      });
    }

    // 方法3: テキストで "Email" を含むリンクを検索
    if (!emailElement) {
      const links = Array.from(document.querySelectorAll('a[role="tab"]'));
      emailElement = links.find(link => {
        const text = (link.textContent || '').trim();
        const span = link.querySelector('span');
        const spanText = span ? (span.textContent || '').trim() : '';
        return text.includes('Email') || text.includes('メール') || 
               spanText === 'Email' || spanText === 'メール';
      });
    }

    if (emailElement) {
      // 要素を画面内にスクロール
      emailElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
      await new Promise(r => setTimeout(r, 300));

      // クリック
      emailElement.click();
      await new Promise(r => setTimeout(r, 500));

      // マウスイベントも発火（React対応）
      const clickEvent = new MouseEvent('click', {
        bubbles: true,
        cancelable: true,
        view: window
      });
      emailElement.dispatchEvent(clickEvent);
      await new Promise(r => setTimeout(r, 200));

      return { didAction: true, reason: 'メールアドレス欄をクリックしました' };
    }

    return { didAction: false, reason: 'メールアドレス欄が見つかりませんでした' };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

(async () => {
  try {
    // Update email addressリンク/ボタンを検索（複数の方法を試す）
    let updateElement = null;

    // 方法1: href="/i/flow/add_email" のリンクを直接検索
    updateElement = document.querySelector('a[href="/i/flow/add_email"]');

    // 方法2: テキストで「Update email address」を含むリンクを検索
    if (!updateElement) {
      const links = Array.from(document.querySelectorAll('a[role="link"], a'));
      updateElement = links.find(link => {
        const text = (link.textContent || '').trim();
        return text === 'Update email address' || text === 'メールアドレスを更新' || 
               text.includes('Update email') || text.includes('メールアドレスを更新');
      });
    }

    // 方法3: ボタンも検索（後方互換性のため）
    if (!updateElement) {
      const buttons = Array.from(document.querySelectorAll('button, [role="button"]'));
      updateElement = buttons.find(btn => {
        const text = (btn.textContent || '').trim();
        return text === 'Update email address' || text === 'メールアドレスを更新' || 
               text.includes('Update email') || text.includes('メールアドレスを更新') ||
               (text.includes('Update') && text.includes('email'));
      });
    }

    if (updateElement) {
      // 要素を画面内にスクロール
      updateElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
      await new Promise(r => setTimeout(r, 300));

      // クリック
      updateElement.click();
      await new Promise(r => setTimeout(r, 500));

      // マウスイベントも発火（React対応）
      const clickEvent = new MouseEvent('click', {
        bubbles: true,
        cancelable: true,
        view: window
      });
      updateElement.dispatchEvent(clickEvent);
      await new Promise(r => setTimeout(r, 200));

      return { didAction: true, reason: 'Update email addressリンク/ボタンをクリックしました' };
    }

    return { didAction: false, reason: 'Update email addressリンク/ボタンが見つかりませんでした' };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

(async () => {
  try {
    const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

    // 1. メールアドレス入力フィールドを検索（複数の方法を試す）
    let emailInput = document.querySelector('input[type="email"], input[name*="email" i]');

    // 方法1: type="email"のinputを検索
    if (!emailInput) {
      emailInput = document.querySelector('input[type="email"]');
    }

    // 方法2: name属性に"email"を含むinputを検索
    if (!emailInput) {
      const inputs = Array.from(document.querySelectorAll('input'));
      emailInput = inputs.find(input => {
        const name = (input.getAttribute('name') || '').toLowerCase();
        return name.includes('email');
      });
    }

    // 方法3: placeholderに"email"を含むinputを検索
    if (!emailInput) {
      const inputs = Array.from(document.querySelectorAll('input'));
      emailInput = inputs.find(input => {
        const placeholder = (input.getAttribute('placeholder') || '').toLowerCase();
        return placeholder.includes('email') || placeholder.includes('メール');
      });
    }

    if (!emailInput) {
      return { didAction: false, reason: 'メールアドレス入力フィールドが見つかりませんでした' };
    }

    // 2. メールアドレスを取得（テンプレート変数は実行時に置換される前提）
    const rawEmail = '{{db_new_email}}';
    const email = (rawEmail || '').trim();

    if (!email || !email.trim()) {
      return { didAction: false, reason: 'db_new_email が指定されていません' };
    }

    // 3. メールアドレス欄に値を設定（React 対応）
    emailInput.focus();
    emailInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
    await sleep(200);

    const setter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value')?.set;
    if (setter) {
      setter.call(emailInput, email);
    } else {
      emailInput.value = email;
    }
    emailInput.dispatchEvent(new Event('input', { bubbles: true }));
    emailInput.dispatchEvent(new Event('change', { bubbles: true }));
    await sleep(300);

    return {
      didAction: true,
      reason: 'メールアドレスを入力しました: ' + email.substring(0, 20) + '...'
    };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

